                const list = saved.map((s, i) => `${i + 1}. ${s.date} ${s.time || ""} | ${s.qty.toLocaleString()}개 | ${s.unitCost.toLocaleString()}원 | 물류${s.logistics.toLocaleString()}원`).join("\n");
