                    {MKT_CATEGORIES.filter((cat) => extraCosts.some((c)=>c.category===cat.key)).map((cat) => <tr key={cat.key} style={{borderBottom:"1px solid #F1F5F9"}}><td style={{padding:"8px 10px",fontWeight:700,whiteSpace:"nowrap",position:"sticky",left:0,background:"#fff",zIndex:1,display:"flex",alignItems:"center",gap:4}}><span style={{width:8,height:8,borderRadius:4,background:cat.color,display:"inline-block"}} /> {cat.icon} {cat.label}</td>{mktHistory.map((m)=>{ const cd=m.catData[cat.key];if(!cd||cd.spend===0) return <td key={m.month} style={{padding:"6px 8px",textAlign:"center",color:"#CBD5E1",fontSize:10}}>-</td>; const v=cd.roas; const bg=v>=500? "#EDE9FE":v>=300? "#ECFDF5":v>=100? "#FFFBEB":"#FEF2F2"; const tc=v>=300? "#059669":v>=100? "#D97706":"#DC2626"; return <td key={m.month} style={{padding:"6px 8px",textAlign:"center",fontFamily:"var(--mono)",fontWeight:600,fontSize:11,background:bg,color:tc,borderRadius:4}}>{Math.round(v)}%</td>})}{(()=>{ const vals=mktHistory.map((m) => m.catData[cat.key]?.roas||0).filter((v) => v>0); const avg=vals.length>0?vals.reduce((a,b)=>a+b,0)/vals.length:0; return <td style={{padding:"6px 10px",textAlign:"center",fontFamily:"var(--mono)",fontWeight:800,fontSize:12,color:"#0F172A"}}>{Math.round(avg)}%</td>})()}</tr>)}
                    <tr style={{borderTop:"2px solid #E2E8F0",background:"#F8FAFC"}}><td style={{padding:"8px 10px",fontWeight:800,position:"sticky",left:0,background:"#F8FAFC",zIndex:1}}>전체 평균</td>{mktHistory.map((m) => { const v=m.overallRoas; const tc=v>=300? "#059669":v>=100? "#D97706":"#DC2626"; return <td key={m.month} style={{padding:"6px 8px",textAlign:"center",fontFamily:"var(--mono)",fontWeight:800,fontSize:11,color:tc}}>{Math.round(v)}%</td>})}<td style={{padding:"6px 10px",textAlign:"center",fontFamily:"var(--mono)",fontWeight:800,fontSize:13,color:"#4F46E5"}}>{Math.round(mktHistory.reduce((s,m)=>s+m.overallRoas,0)/mktHistory.length)}%</td></tr>
