                {savedScenarios.map((sc,idx)=>{ const pD=sc.profit-metrics.totalOpProfit; const iI=pD>0; return <div key={sc.id} style={{minWidth:200,background:iI? "#F0FDF4":"#FFF7ED",borderRadius:14,padding:16,border:`2px solid ${iI? "#86EFAC":"#FDBA74"}`,flexShrink:0,position:"relative"}}><button onClick={()=>setSavedScenarios((prev) => prev.filter((s)=>s.id!==sc.id))} style={{position:"absolute",top:8,right:8,background:"none",border:"none",cursor:"pointer",fontSize:14,color:"#94A3B8",padding:0,lineHeight:1}}>×</button><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}><span style={{fontSize:13,fontWeight:800,color:"#0F172A"}}>🔖 {sc.label}</span><MiniGauge score={sc.score} size={32} /></div><div style={{fontSize:10,color:"#94A3B8",marginBottom:8}}>{sc.ts} 저장</div>{[{l:"매출",v:fmt(sc.revenue)},{l:"영업이익",v:fmt(sc.profit),c:sc.profit>=0? "#10B981":"#EF4444"},{l:"이익률",v:`${sc.opMargin}%`},{l:"ROAS",v:`${sc.roas}%`},{l:"연 ROI",v:`${sc.annualROI}%`},].map((r,i)=><div key={i} style={{display:"flex",justifyContent:"space-between",paddingTop:4,paddingBottom:4,borderBottom:i<4? "1px solid rgba(0,0,0,0.06)":"none"}}><span style={{fontSize:11,color:"#64748B"}}>{r.l}</span><span style={{fontSize:12,fontWeight:700,fontFamily:"var(--mono)",color:r.c||"#0F172A"}}>{r.v}</span></div>)}<div style={{display:"flex",flexWrap:"wrap",gap:4,marginTop:8}}>{sc.adChg!==0&&<span style={{fontSize:9,padding:"2px 6px",borderRadius:4,background:"#EDE9FE",color:"#6D28D9",fontWeight:600}}>광고 {sc.adChg>0? "+":""}{sc.adChg}%</span>}{sc.priceChg!==0&&<span style={{fontSize:9,padding:"2px 6px",borderRadius:4,background:"#ECFDF5",color:"#059669",fontWeight:600}}>가격 {sc.priceChg>0? "+":""}{sc.priceChg}%</span>}{sc.retChg!==0&&<span style={{fontSize:9,padding:"2px 6px",borderRadius:4,background:"#FEF3C7",color:"#92400E",fontWeight:600}}>반품 {sc.retChg>0? "+":""}{sc.retChg}%p</span>}{sc.targetRoas!==0&&<span style={{fontSize:9,padding:"2px 6px",borderRadius:4,background:"#CFFAFE",color:"#0E7490",fontWeight:600}}>ROAS {sc.targetRoas>0? "+":""}{sc.targetRoas}%p</span>}</div><div style={{marginTop:8,padding:"6px 10px",borderRadius:8,background:iI? "#DCFCE7":"#FEE2E2",display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{fontSize:10,fontWeight:600,color:iI? "#166534":"#991B1B"}}>이익 변동</span><span style={{fontSize:12,fontWeight:800,fontFamily:"var(--mono)",color:iI? "#166534":"#991B1B"}}>{pD>=0? "▲":"▼"} {fmt(Math.abs(pD))}</span></div></div>;})}
                {/* "Load" button to apply a saved scenario */}
